CREATE TABLE "game_sessions" ("id" UUID NOT NULL, "anonymousId" UUID NOT NULL, "status" TEXT NOT NULL, "configVersion" TEXT NOT NULL, "seedEncrypted" TEXT, "stateVersion" INTEGER NOT NULL DEFAULT 0, "setup" JSONB NOT NULL, "currentState" JSONB NOT NULL, "utm" JSONB, "referrer" TEXT, "landingUrl" TEXT, "startedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "lastEventAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "finishedAt" TIMESTAMP(3), "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "game_sessions_pkey" PRIMARY KEY ("id"));
CREATE TABLE "game_events" ("id" UUID NOT NULL, "sessionId" UUID NOT NULL, "sequenceNumber" INTEGER NOT NULL, "commandId" TEXT NOT NULL, "eventType" TEXT NOT NULL, "gameDay" INTEGER NOT NULL, "payload" JSONB NOT NULL, "idempotencyKey" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "game_events_pkey" PRIMARY KEY ("id"));
CREATE TABLE "game_results" ("id" UUID NOT NULL, "sessionId" UUID NOT NULL, "configVersion" TEXT NOT NULL, "metrics" JSONB NOT NULL, "targets" JSONB NOT NULL, "financials" JSONB NOT NULL, "strongDecisions" JSONB NOT NULL, "bottlenecks" JSONB NOT NULL, "counterfactuals" JSONB NOT NULL, "finalStatus" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "game_results_pkey" PRIMARY KEY ("id"));
CREATE TABLE "ai_reports" ("id" UUID NOT NULL, "sessionId" UUID NOT NULL, "provider" TEXT NOT NULL, "model" TEXT NOT NULL, "promptVersion" TEXT NOT NULL, "status" TEXT NOT NULL, "report" JSONB, "errorCode" TEXT, "latencyMs" INTEGER NOT NULL, "inputTokens" INTEGER, "outputTokens" INTEGER, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "ai_reports_pkey" PRIMARY KEY ("id"));
CREATE TABLE "leads" ("id" UUID NOT NULL, "sessionId" UUID NOT NULL, "name" TEXT NOT NULL, "contactEncrypted" TEXT NOT NULL, "product" TEXT NOT NULL, "productPrice" INTEGER NOT NULL, "socialLink" TEXT, "comment" TEXT, "privacyConsentAt" TIMESTAMP(3) NOT NULL, "marketingConsentAt" TIMESTAMP(3), "deliveryStatus" TEXT NOT NULL, "deliveryAttempts" INTEGER NOT NULL DEFAULT 0, "webhookLastError" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "deliveredAt" TIMESTAMP(3), CONSTRAINT "leads_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "game_events_idempotencyKey_key" ON "game_events"("idempotencyKey");
CREATE UNIQUE INDEX "game_events_sessionId_sequenceNumber_key" ON "game_events"("sessionId", "sequenceNumber");
CREATE UNIQUE INDEX "game_events_sessionId_commandId_key" ON "game_events"("sessionId", "commandId");
CREATE UNIQUE INDEX "game_results_sessionId_key" ON "game_results"("sessionId");
ALTER TABLE "game_events" ADD CONSTRAINT "game_events_sessionId_fkey" FOREIGN KEY ("sessionId") REFERENCES "game_sessions"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "game_results" ADD CONSTRAINT "game_results_sessionId_fkey" FOREIGN KEY ("sessionId") REFERENCES "game_sessions"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "ai_reports" ADD CONSTRAINT "ai_reports_sessionId_fkey" FOREIGN KEY ("sessionId") REFERENCES "game_sessions"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "leads" ADD CONSTRAINT "leads_sessionId_fkey" FOREIGN KEY ("sessionId") REFERENCES "game_sessions"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
